mapper.select:
SELECT cu.*, g.branch_code
FROM crm_users cu
JOIN gym g ON cu.gym_id = g.id
WHERE g.branch_code = #{branchCode}
  AND cu.username   = #{username}
  AND cu.is_active  = 1

SELECT cu.*, g.branch_code
FROM crm_users cu
JOIN gym g ON cu.gym_id = g.id
WHERE cu.gym_id   = #{gymId}
  AND cu.username = #{username}
  AND cu.is_active = 1
